    uint32_t inFeatures = x_shape.GetDim(1);
    const auto &weight_shape = context->GetInputShape(1)->GetOriginShape();
    uint32_t outFeatures = weight_shape.GetDim(0);
    uint32_t totalLength = batchSize * outFeatures;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int32_t numGroups = attrs->GetAttrPointer<int32_t>(0)[0];
    float eps = attrs->GetAttrPointer<float>(1)[0];

    // Simple tiling: each core processes a contiguous chunk of output rows
    uint32_t tileLen = totalLength;
